    .Where(m => (m.Name == "AreEqual" || m.Name == "AreNotEqual" || m.Name == "AreSame") && m.IsGenericMethod);
foreach (var m in methods)
{
    var genArgs = m.GetGenericArguments();
    foreach (var g in genArgs)
    {
        var constraints = g.GetGenericParameterConstraints();
        var attrs = g.GenericParameterAttributes;
        Console.WriteLine($"{m.Name} - {g.Name}: constraints=[{string.Join(",", constraints.Select(c => c.Name))}] attrs={attrs}");
    }
}
